import jsPDF from 'jspdf'
import 'jspdf-autotable'

const SAPPHIRE_LOGO = 'data:image/png;base64,'
const QR_CODE = 'data:image/png;base64,'
const PTSDA_LOGO = 'data:image/png;base64,'

const BANK_DETAILS = {
  accountName: 'SAPPHIRE SALES CORPORATION PRIVATE LIMITED',
  accountNo: '50200047645902',
  bankName: 'HDFC Bank',
  branch: 'Bhandarkar Road & HDFC0000007',
}

const TERMS = [
  '1. Payment 100% in Advance.',
  '2. Local Transport Extra.',
  '3. Unloading at site by Customer',
  '4. Goods sold will not be returned/replaced/exchanged.',
]

function numberToWords(num) {
  const ones = ['', 'One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven', 'Eight',
    'Nine', 'Ten', 'Eleven', 'Twelve', 'Thirteen', 'Fourteen', 'Fifteen', 'Sixteen',
    'Seventeen', 'Eighteen', 'Nineteen']
  const tens = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety']
  if (num === 0) return 'Zero only'
  function convert(n) {
    if (n < 20) return ones[n]
    if (n < 100) return tens[Math.floor(n / 10)] + (n % 10 ? ' ' + ones[n % 10] : '')
    if (n < 1000) return ones[Math.floor(n / 100)] + ' Hundred' + (n % 100 ? ' ' + convert(n % 100) : '')
    if (n < 100000) return convert(Math.floor(n / 1000)) + ' Thousand' + (n % 1000 ? ' ' + convert(n % 1000) : '')
    if (n < 10000000) return convert(Math.floor(n / 100000)) + ' Lakh' + (n % 100000 ? ' ' + convert(n % 100000) : '')
    return convert(Math.floor(n / 10000000)) + ' Crore' + (n % 10000000 ? ' ' + convert(n % 10000000) : '')
  }
  return convert(Math.round(num)) + ' only'
}

function formatDate(dateStr) {
  if (!dateStr) return ''
  const d = new Date(dateStr)
  return d.toLocaleDateString('en-IN', { day: '2-digit', month: '2-digit', year: 'numeric' })
}

function calcItem(item) {
  const qty = Number(item.quantity) || 0
  const price = Number(item.price) || 0
  const disc = Number(item.discount) || 0
  const taxRate = Number(item.tax_rate) || 0.18
  const taxableValue = qty * price * (1 - disc / 100)
  const gstAmount = taxableValue * taxRate
  return { qty, price, disc, taxableValue, gstAmount, totalValue: taxableValue + gstAmount, taxRate }
}

export function previewSaleOrderPDF(order) {
  const doc = _buildDoc(order)
  const blobUrl = doc.output('bloburl')
  window.open(blobUrl, '_blank')
}

export function generateSaleOrderPDF(order) {
  const doc = _buildDoc(order)
  return doc
}

function _buildDoc(order) {
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' })
  const pw = 210, ml = 10, mr = 10, cw = pw - ml - mr
  const halfX = ml + cw / 2

  const BLACK = [0, 0, 0]
  const WHITE = [255, 255, 255]
  const LGRAY = [180, 180, 180]
  const BGRAY = [235, 235, 235]

  const client = order.client_snapshot || {}
  const items = order.items || []

  // ── HEADER ────────────────────────────────────────────────────────────────
  // Title
  doc.setFontSize(11)
  doc.setFont('helvetica', 'bold')
  doc.setTextColor(...BLACK)
  doc.text('Sales Quotation', pw / 2, 11, { align: 'center' })

  // Sapphire logo — left (543x222 aspect = 2.446:1, at 42mm wide = 17mm tall)
  doc.addImage(SAPPHIRE_LOGO, 'PNG', ml, 13, 42, 17)

  // PTSDA logo — right (120x106 aspect = 1.13:1, at 18mm wide = 16mm tall)
  // Box border around PTSDA
  doc.setDrawColor(...LGRAY)
  doc.setLineWidth(0.3)
  doc.rect(ml + cw - 22, 13, 22, 22)
  doc.addImage(PTSDA_LOGO, 'PNG', ml + cw - 20, 14, 18, 16)
  doc.setFontSize(6.5)
  doc.setFont('helvetica', 'bold')
  doc.setTextColor(...BLACK)
  doc.text('Member', ml + cw - 11, 32, { align: 'center' })
  doc.text('PTSDA', ml + cw - 11, 35.5, { align: 'center' })

  // Company name — center
  const cx = ml + 44  // start after sapphire logo
  const cxEnd = ml + cw - 24  // end before PTSDA box
  const centerW = cxEnd - cx
  const centerMid = cx + centerW / 2

  doc.setFontSize(10.5)
  doc.setFont('helvetica', 'bold')
  doc.text('SAPPHIRE SALES CORPORATION PRIVATE LIMITED', centerMid, 17, { align: 'center' })
  doc.setFontSize(6.5)
  doc.setFont('helvetica', 'normal')
  doc.text('S.No.66/19, Katraj-Kondhwa Road, Opp. Shatrunjay Temple, Near Kanha Hotel,', centerMid, 21, { align: 'center' })
  doc.text('Kondhwa (Bk) Pune - 411048 Maharashtra, India  Ph.+91 7887859228', centerMid, 24.5, { align: 'center' })
  doc.text('Email : orders@sapphiresalespune.com  |  Website : www.sapphiresalespune.com', centerMid, 28, { align: 'center' })
  doc.text('GSTIN : 27ABCCS3513N1Z5   CIN NO : U74999PN2019PTC185412   PAN NO : ABCCS3513N', centerMid, 31.5, { align: 'center' })

  // Bottom border of header
  doc.setDrawColor(...LGRAY)
  doc.setLineWidth(0.4)
  doc.line(ml, 37, ml + cw, 37)

  // ── CUSTOMER + META BOX ───────────────────────────────────────────────────
  let y = 39
  const boxH = 52
  doc.setDrawColor(...LGRAY)
  doc.setLineWidth(0.3)
  doc.rect(ml, y, cw, boxH)
  doc.line(halfX, y, halfX, y + boxH)

  // LEFT — Customer info (all fields, no internal divider)
  doc.setFontSize(7.5)
  doc.setFont('helvetica', 'bold')
  doc.setTextColor(...BLACK)
  doc.text('Customer Code : ', ml + 2, y + 6)
  doc.setFont('helvetica', 'normal')
  doc.text(client.customer_code || '', ml + 32, y + 6)

  doc.setFont('helvetica', 'bold')
  doc.text('Customer Name : ', ml + 2, y + 12)
  doc.text(client.name || '', ml + 32, y + 12)

  doc.setFont('helvetica', 'normal')
  doc.setFontSize(7)
  const addrLines = doc.splitTextToSize('Address : ' + (client.address || ''), halfX - ml - 4)
  doc.text(addrLines, ml + 2, y + 18)

  // Contact fields below address (no divider line)
  doc.text('Contact Person : ' + (client.contact_person || ''), ml + 2, y + 29)
  doc.text('Contact Person No : ' + (client.phone || ''), ml + 2, y + 34)
  doc.text('Email ID : ' + (client.email || ''), ml + 2, y + 39)
  doc.text('GST No : ' + (client.gst_no || ''), ml + 2, y + 44)
  doc.text('PAN No : ' + (client.pan_no || ''), ml + 2, y + 49)

  // RIGHT — Quotation meta (5 rows, no blank row, no internal divider)
  const rX = halfX + 2
  const metaRows = [
    ['Quotation No.', ':  ' + (order.so_number || '')],
    ['Quotation Date', ':  ' + formatDate(order.so_date)],
    ['Despatch Through', ':'],
    ['Payment Terms', ':  ' + (order.payment_terms || 'Net-30')],
    ['Salesman', ':  ' + (order.salesperson_name || '')],
  ]
  doc.setFontSize(7.5)
  metaRows.forEach(([label, value], i) => {
    const ry = y + 7 + i * 6.5
    doc.setFont('helvetica', 'bold')
    doc.text(label, rX, ry)
    doc.setFont('helvetica', 'normal')
    doc.text(String(value), rX + 34, ry)
  })

  // ── ITEMS TABLE ───────────────────────────────────────────────────────────
  y += 54

  const totals = items.reduce((acc, item) => {
    const c = calcItem(item)
    acc.totalQty += c.qty
    acc.taxableValue += c.taxableValue
    acc.gstAmount += c.gstAmount
    acc.totalValue += c.totalValue
    return acc
  }, { totalQty: 0, taxableValue: 0, gstAmount: 0, totalValue: 0 })

  const transportAmt = Number(order.transport_charges) || 0
  // Transport is taxable at 18% — add to taxable value, then calculate combined GST
  const totalTaxableValue = totals.taxableValue + transportAmt
  const totalGST = totalTaxableValue * 0.18   // single GST on everything combined
  const totalWithTransport = totalTaxableValue + totalGST
  const roundedOff = Math.round(totalWithTransport) - totalWithTransport
  const finalTotal = Math.round(totalWithTransport)
  const cgst = totalGST / 2
  const sgst = totalGST / 2

  doc.autoTable({
    startY: y,
    margin: { left: ml, right: mr },
    head: [['S.\nNO', 'Description of the Material', 'HSN', 'UOM', 'Qty', 'Price', 'Disc\n%', 'GST\n%', 'Taxable\nValue']],
    body: items.map((item, i) => {
      const c = calcItem(item)
      return [
        i + 1, item.description, item.hsn_code || '', item.uom || 'NOS',
        c.qty.toFixed(2),
        Number(item.price).toLocaleString('en-IN', { minimumFractionDigits: 2 }),
        c.disc.toFixed(2), (c.taxRate * 100).toFixed(2),
        c.taxableValue.toLocaleString('en-IN', { minimumFractionDigits: 2 }),
      ]
    }),
    foot: [
      // Transport charges row (only if transport > 0)
      ...(transportAmt > 0 ? [
        [{ content: 'Transport Charges', colSpan: 8, styles: { halign: 'right' } }, { content: transportAmt.toLocaleString('en-IN', { minimumFractionDigits: 2 }), styles: { halign: 'right' } }],
      ] : []),
      // Total taxable value (items + transport combined)
      [{ content: 'Total Quantity / Taxable Value', colSpan: 4, styles: { halign: 'right', fontStyle: 'bold' } }, { content: totals.totalQty.toFixed(2), styles: { halign: 'center', fontStyle: 'bold' } }, { content: '', colSpan: 3 }, { content: totalTaxableValue.toLocaleString('en-IN', { minimumFractionDigits: 2 }), styles: { halign: 'right', fontStyle: 'bold' } }],
      // Single combined GST
      [{ content: 'Output CGST @ 9%', colSpan: 8, styles: { halign: 'right' } }, { content: cgst.toLocaleString('en-IN', { minimumFractionDigits: 2 }), styles: { halign: 'right' } }],
      [{ content: 'Output SGST @ 9%', colSpan: 8, styles: { halign: 'right' } }, { content: sgst.toLocaleString('en-IN', { minimumFractionDigits: 2 }), styles: { halign: 'right' } }],
      [{ content: 'Rounded Off', colSpan: 8, styles: { halign: 'right' } }, { content: roundedOff.toFixed(2), styles: { halign: 'right' } }],
      [{ content: 'Total Value', colSpan: 8, styles: { halign: 'right', fontStyle: 'bold', fontSize: 8.5 } }, { content: finalTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 }), styles: { halign: 'right', fontStyle: 'bold', fontSize: 8.5 } }],
    ],
    headStyles: { fillColor: BGRAY, textColor: BLACK, fontSize: 7, fontStyle: 'bold', halign: 'center', lineColor: LGRAY, lineWidth: 0.3 },
    bodyStyles: { fontSize: 7, textColor: BLACK, lineColor: LGRAY, lineWidth: 0.2 },
    footStyles: { fillColor: WHITE, textColor: BLACK, fontSize: 7.5, lineColor: LGRAY, lineWidth: 0.2 },
    columnStyles: {
      0: { halign: 'center', cellWidth: 8 },
      1: { cellWidth: 'auto' },
      2: { halign: 'center', cellWidth: 18 },
      3: { halign: 'center', cellWidth: 12 },
      4: { halign: 'center', cellWidth: 12 },
      5: { halign: 'right', cellWidth: 18 },
      6: { halign: 'center', cellWidth: 12 },
      7: { halign: 'center', cellWidth: 12 },
      8: { halign: 'right', cellWidth: 22 },
    },
    tableLineColor: LGRAY,
    tableLineWidth: 0.3,
  })

  let finalY = doc.lastAutoTable.finalY + 2
  const pageH = 295
  const bottomMargin = 12

  function checkPageBreak(neededH) {
    if (finalY + neededH > pageH - bottomMargin) {
      doc.addPage()
      finalY = 12
    }
  }

  // ── TOTAL IN WORDS ────────────────────────────────────────────────────────
  checkPageBreak(10)
  doc.setDrawColor(...LGRAY)
  doc.setLineWidth(0.3)
  doc.rect(ml, finalY, cw, 8)
  doc.setFontSize(7.5)
  doc.setFont('helvetica', 'bold')
  doc.setTextColor(...BLACK)
  doc.text('Total Value In Words : ', ml + 2, finalY + 5)
  doc.setFont('helvetica', 'normal')
  doc.text(numberToWords(finalTotal), ml + 40, finalY + 5)
  finalY += 10

  // ── REMARKS ───────────────────────────────────────────────────────────────
  if (order.notes) {
    doc.setFontSize(7)
    doc.setFont('helvetica', 'normal')
    const remarkLines = doc.splitTextToSize(order.notes, cw - 4)
    const lineH = 5
    const remarkBoxH = Math.max(14, 6 + remarkLines.length * lineH + 4)
    checkPageBreak(remarkBoxH + 2)
    doc.setDrawColor(...LGRAY)
    doc.setLineWidth(0.3)
    doc.rect(ml, finalY, cw, remarkBoxH)
    doc.setFont('helvetica', 'bold')
    doc.setFontSize(7.5)
    doc.setTextColor(...BLACK)
    doc.text('Remarks :', ml + 2, finalY + 5)
    doc.setFont('helvetica', 'normal')
    doc.setFontSize(7)
    doc.text(remarkLines, ml + 2, finalY + 11)
    finalY += remarkBoxH + 2
  }

  // ── BANK DETAILS + TERMS ──────────────────────────────────────────────────
  const bankBoxH = 36
  checkPageBreak(bankBoxH + 2)
  doc.setDrawColor(...LGRAY)
  doc.setLineWidth(0.3)
  doc.rect(ml, finalY, cw, bankBoxH)
  doc.line(halfX, finalY, halfX, finalY + bankBoxH)

  doc.setFontSize(7.5)
  doc.setFont('helvetica', 'bold')
  doc.setTextColor(...BLACK)
  doc.text("Company's Bank Details :", ml + 2, finalY + 6)
  doc.setFont('helvetica', 'normal')
  doc.setFontSize(7)
  doc.text('Account Name : ' + BANK_DETAILS.accountName, ml + 2, finalY + 12)
  doc.text('Bank Name : ' + BANK_DETAILS.bankName, ml + 2, finalY + 18)
  doc.text('A/C No. : ' + BANK_DETAILS.accountNo, ml + 2, finalY + 24)
  doc.text('Branch & IFS Code : ' + BANK_DETAILS.branch, ml + 2, finalY + 30)

  doc.setFont('helvetica', 'bold')
  doc.setFontSize(7.5)
  doc.text('Terms & Conditions :', rX, finalY + 6)
  doc.setFont('helvetica', 'normal')
  doc.setFontSize(7)
  TERMS.forEach((t, i) => doc.text(t, rX, finalY + 13 + i * 5.5))
  finalY += bankBoxH + 2

  // ── SIGNATORY + QR CODE ───────────────────────────────────────────────────
  const sigBoxH = 36
  checkPageBreak(sigBoxH + 2)
  doc.setDrawColor(...LGRAY)
  doc.setLineWidth(0.3)
  doc.rect(ml, finalY, cw, sigBoxH)
  doc.line(halfX, finalY, halfX, finalY + sigBoxH)

  const qrSize = 28
  const qrX = ml + (halfX - ml) / 2 - qrSize / 2
  const qrY = finalY + 3
  doc.addImage(QR_CODE, 'PNG', qrX, qrY, qrSize, qrSize)
  doc.setFontSize(7)
  doc.setFont('helvetica', 'normal')
  doc.setTextColor(...BLACK)
  doc.text('Scan for UPI Payment', ml + (halfX - ml) / 2, qrY + qrSize + 4, { align: 'center' })

  doc.setFontSize(8)
  doc.setFont('helvetica', 'bold')
  doc.text('For SAPPHIRE SALES CORPORATION PRIVATE LIMITED', rX, finalY + 10)
  doc.setFont('helvetica', 'normal')
  doc.setFontSize(7)
  doc.text('Authorised Signatory', rX, finalY + 30)

  // ── PAGE NUMBERS ──────────────────────────────────────────────────────────
  const pageCount = doc.internal.getNumberOfPages()
  for (let i = 1; i <= pageCount; i++) {
    doc.setPage(i)
    doc.setFontSize(7)
    doc.setTextColor(120, 120, 120)
    doc.text(`Page ${i} of ${pageCount}`, pw - mr, 290, { align: 'right' })
  }

  return doc
}
